let userBalance=0,vpsCount=0,domainsCount=0,pendingTransactions=0,welcomeUsername="";const _apiCache={};function apiFetch(n){return _apiCache[n]||(_apiCache[n]=fetch(n).then((n=>n.json()))),_apiCache[n]}async function initializeDashboard(){try{window.INIT_DATA?(userBalance=window.INIT_DATA.balance,welcomeUsername=window.INIT_DATA.username,vpsCount=window.INIT_DATA.vpsCount,domainsCount=window.INIT_DATA.domainCount,pendingTransactions=window.INIT_DATA.pendingCount):await Promise.all([loadBalanceOnly(),loadVPSCountOnly(),loadDomainsCountOnly(),loadPendingTransactionsCount()]),document.getElementById("initialLoading").style.display="none";const n=window.INIT_DATA?window.INIT_DATA.isNewUser:userBalance<=0&&0===vpsCount&&0===domainsCount&&0===pendingTransactions;if(document.getElementById("globalNewsSection").style.display="block",loadRecentNews(),n){const n=document.getElementById("welcomeGreeting");n&&welcomeUsername&&(n.textContent="Hola, "+welcomeUsername+" 👋"),document.getElementById("welcomeScreen").style.display="block"}else document.getElementById("dashboardContent").style.display="block",loadFullDashboard()}catch(n){console.error("Error initializing dashboard:",n);const t=document.getElementById("initialLoading");t&&(t.innerHTML=`\n                <i class="fas fa-exclamation-triangle" style="font-size: 3rem; color: #ef4444; margin-bottom: 20px;"></i>\n                <p style="font-size: 1.1rem; color: #ef4444;">${LANG.dash_err_loading}</p>\n            `)}}async function loadBalanceOnly(){try{const n=await apiFetch("../api/users/me");n.success&&n.data&&(userBalance=parseFloat(n.data.balance)||0,welcomeUsername=n.data.username||"")}catch(n){console.error("Error loading balance:",n)}}async function loadVPSCountOnly(){try{const n=await apiFetch("../api/servers/list");n.success&&n.data&&(vpsCount=n.data.length)}catch(n){console.error("Error loading VPS count:",n)}}async function loadDomainsCountOnly(){try{const n=await apiFetch("../api/domains/list");n.success&&n.data&&(domainsCount=n.data.length)}catch(n){console.error("Error loading domains count:",n)}}async function loadPendingTransactionsCount(){try{const n=await apiFetch("../api/orders/list");n.success&&n.data&&(pendingTransactions=n.data.filter((n=>{const t=(n.status||"").toUpperCase();return"COMPLETED"!==t&&"FAILED"!==t&&"REJECTED"!==t})).length)}catch(n){console.error("Error loading pending transactions:",n)}}async function loadFullDashboard(){await Promise.all([loadBalance(),loadVPSList(),loadRecentTransactions(),loadDomains()])}async function loadBalance(){try{const n=await apiFetch("../api/users/me");if(n.success&&n.data){const t=parseFloat(n.data.balance)||0;userBalance=t;const a=document.getElementById("totalBalance");a&&(a.textContent=`$${t.toFixed(2)}`)}}catch(n){console.error("Error loading balance:",n)}}async function loadVPSList(){try{const n=await apiFetch("../api/servers/list"),t=document.getElementById("vpsList");if(!t)return;if(n.success&&n.data&&n.data.length>0){vpsCount=n.data.length;const a=document.getElementById("totalVPS");a&&(a.textContent=n.data.length);const e=Date.now(),s=e+864e5,i=n.data.filter((n=>{if(!n.expires_at||"SUSPENDED"===n.status||"TERMINATED"===n.status)return!1;const t=new Date(n.expires_at).getTime();return t>e&&t<=s}));if(i.length>0){const n=document.getElementById("vpsExpiryWarning"),t=document.getElementById("vpsExpiryText");if(n&&t){const a=i.map((n=>`<strong>${n.name}</strong>`)).join(", "),e=1===i.length?"se suspenderá":"se suspenderán";t.innerHTML=`Atención: ${a} ${e} en menos de 24 horas. Renueva tu plan para evitar la suspensión.`,n.style.display="block"}}const o=n.data.slice(0,5);t.innerHTML=o.map((n=>{const t=n.status||"unknown";let a="status-inactive",e=LANG.status_inactive;"ACTIVE"===t?(a="status-active",e=LANG.status_active):"PROVISIONING"===t?(a="status-provisioning",e=LANG.status_provisioning):"INACTIVE"===t&&(a="status-inactive",e=LANG.status_inactive);const s=n.specs&&n.specs.ram?n.specs.ram:"N/A";return`\n                    <div class="vps-mini-card" onclick="window.location.href='manage/?id=${n.id}'">\n                        <div class="vps-info">\n                            <div class="vps-name">${n.name||"VPS-"+n.id}</div>\n                            <div class="vps-specs">\n                                ${n.specs?n.specs.cpu:"N/A"} • ${s} • \n                                ${n.ip||LANG.status_pending+"..."}\n                            </div>\n                        </div>\n                        <span class="vps-status ${a}">${e}</span>\n                    </div>\n                `})).join("")}else{const n=document.getElementById("totalVPS");n&&(n.textContent="0"),t.innerHTML=`\n                <div class="empty-state">\n                    <i class="fas fa-server"></i>\n                    <p>${LANG.dash_no_servers}</p>\n                    <a href="vps" class="btn btn-manage" style="margin-top: 10px;">\n                        <i class="fas fa-plus"></i> ${LANG.dash_btn_create_server}\n                    </a>\n                </div>\n            `}}catch(n){console.error("Error loading VPS:",n);const t=document.getElementById("vpsList");t&&(t.innerHTML=`<div class="empty-state" style="color: #ef4444;">${LANG.dash_err_servers}</div>`)}}async function loadRecentNews(){const n=document.getElementById("newsListHome");if(n)try{const t=await fetch("../api/news/list?page=1&limit=3"),a=await t.json();a.success&&a.data&&a.data.length>0?n.innerHTML='<div class="news-mini-list">'+a.data.map((n=>{const t=new Date(n.created_at).toLocaleDateString(LANG.txt_date_format,{day:"numeric",month:"short",year:"numeric"});return`\n                    <div class="news-mini-card" onclick="window.location.href='news/detail?id=${n.id}'">\n                        <span class="news-mini-badge">${n.category}</span>\n                        <div class="news-mini-title">${n.title}</div>\n                        <div class="news-mini-date">\n                            <i class="far fa-calendar-alt"></i> ${t}\n                        </div>\n                    </div>\n                `})).join("")+"</div>":n.innerHTML=`\n                <div class="empty-state">\n                    <i class="far fa-newspaper"></i>\n                    <p>${LANG.news_no_items}</p>\n                </div>\n            `}catch(t){console.error("Error loading news:",t),n.innerHTML=""}}async function loadRecentTransactions(){const n=document.getElementById("transactionsList");if(n)try{const t=await fetch("../api/transactions/list?limit=5&page=1"),a=await t.json();a.success&&a.data&&a.data.length>0?n.innerHTML='<ul class="item-list">'+a.data.map((n=>{const t=(n.status||"").toLowerCase();let a="status-inactive",e=t;switch(t){case"completed":a="status-active",e=LANG.status_completed;break;case"pending":case"confirming":a="status-provisioning",e=LANG.status_pending;break;case"failed":a="status-inactive",e=LANG.status_failed}const s=new Date(n.created_at).toLocaleDateString(LANG.txt_date_format,{year:"numeric",month:"short",day:"numeric"});return`\n                    <li>\n                        <div class="item-info">\n                            <div class="item-title">${n.description||n.type||"Transaction"}</div>\n                            <div class="item-meta">${s} · ${n.payment_currency||n.currency||""}</div>\n                        </div>\n                        <span class="item-badge ${a}">$${parseFloat(n.amount||0).toFixed(2)} · ${e}</span>\n                    </li>`})).join("")+"</ul>":n.innerHTML=`\n                <div class="empty-state">\n                    <i class="fas fa-exchange-alt"></i>\n                    <p>${LANG.dash_no_orders}</p>\n                </div>`}catch(t){n.innerHTML=`<div class="empty-state" style="color:#ef4444;">${LANG.dash_err_orders}</div>`}}async function loadDomains(){try{const n=await apiFetch("../api/domains/list");if(n.success&&n.data){domainsCount=n.data.length;const t=document.getElementById("totalDomains");t&&(t.textContent=n.data.length)}}catch(n){console.error("Error loading domains:",n)}}document.addEventListener("DOMContentLoaded",initializeDashboard);